function backFromProduct(){
  closeProductDetail();
  if(isShopPage()){
    var shop=document.querySelector(".shop-grid")||document.querySelector(".shop-intro")||document.body;
    setTimeout(function(){shop.scrollIntoView({behavior:"smooth",block:"start"});},80);
  }else{
    window.location.href="shop.html";
  }
}
function openProd(id,nav){
  ensureProductDetail();
  var prod=null;
  for(var i=0;i<T[lang].products.length;i++){if(T[lang].products[i].id===id){prod=T[lang].products[i];break;}}
  if(!prod)return;
  curProd=prod;selSz=null;selColor="";selVariantImages=[];
  el("pdImg").innerHTML=productCarouselHTML(prod,"pd");
  set("pd-nm",prod.name);set("pd-sub",prod.sub);
  var priceEl=el("pd-pr");
  if(priceEl){
    if(productPriceVisible(prod)){
      priceEl.textContent="€ "+Number(prod.price||0).toLocaleString("it-IT");
      priceEl.style.display="";
    }else{
      priceEl.textContent="";
      priceEl.style.display="none";
    }
  }
  set("pd-story",prod.story);
  var storyEl=el("pd-story");if(storyEl)storyEl.style.display=prod.story?"":"none";
  renderColorVariants(prod);
  var t=T[lang];set("artB",t.artText);set("delB",t.delText);
  var szHtml="",sizes=prod.sizes||[];
  set("pd-back",t.pdBack);set("sz-lbl",t.szLbl);set("atcBtn",t.addBtn);set("wishBtn",t.wishBtn);
  for(var j=0;j<sizes.length;j++)szHtml+='<div class="sz-opt" onclick="pickSz(this,\''+jsString(sizes[j])+'\')">'+sizes[j]+'</div>';
  el("szRow").innerHTML=szHtml;
  var acc=el("productAcc");if(acc)acc.innerHTML=productAccordionsHTML(prod);
  if(nav!==false)showProductDetail();
}
function pickSz(btn,sz){var opts=document.querySelectorAll(".sz-opt");for(var i=0;i<opts.length;i++)opts[i].classList.remove("sel");btn.classList.add("sel");selSz=sz;}
function splitColorNames(value){
  var text=String(value||"").trim();
  if(!text)return [];
  var parts=text.indexOf(";")!==-1?text.split(";"):text.split(/\s*,\s*/);
  return parts.map(function(v){return v.trim();}).filter(Boolean);
}
function parseColorVariants(prod){
  var details=prod&&prod.details?prod.details:{};
  var raw=details.varianti_colore||details.varianti||details.color_variants||"";
  var explicit=String(raw||"").split(/\n+/).map(function(line){
    line=line.trim();
    if(!line)return null;
    var parts=line.split(/\s*\|\s*/);
    if(parts.length<2)parts=line.split(/\s*:\s*/);
    var name=(parts[0]||"").trim();
    var imgs=(parts.slice(1).join("|")||"").split(/\s*;\s*|\s*,\s*/).map(function(v){return v.trim();}).filter(Boolean);
    if(!name||!imgs.length)return null;
    return {name:name,images:imgs};
  }).filter(Boolean);
  if(explicit.length)return explicit;
  var names=splitColorNames(details.colore);
  var imgs=productImages(prod);
  if(names.length<2||imgs.length<2)return [];
  var per=Math.ceil(imgs.length/names.length);
  return names.map(function(name,index){
    var slice=imgs.slice(index*per,(index+1)*per);
    return slice.length?{name:name,images:slice}:null;
  }).filter(Boolean);
}
function renderColorVariants(prod){
  var block=el("colorVariantBlock"),row=el("colorRow");
  if(!block||!row)return;
  var variants=parseColorVariants(prod);
  if(!variants.length){
    selColor=(prod.details&&prod.details.colore)?prod.details.colore:"";
    selVariantImages=productImages(prod);
    if(selColor){
      block.style.display="";
      row.innerHTML='<span class="color-opt color-static">'+escHtml(selColor)+'</span>';
    }else{
      block.style.display="none";
      row.innerHTML="";
    }
    return;
  }
  block.style.display="";
  var html="";
  for(var i=0;i<variants.length;i++){
    html+='<button type="button" class="color-opt '+(i===0?"sel":"")+'" onclick="pickColorVariant(this,\''+jsString(prod.id)+'\','+i+')">'+escHtml(variants[i].name)+'</button>';
  }
  row.innerHTML=html;
  if(variants[0]){
    selColor=variants[0].name;
    selVariantImages=variants[0].images.slice();
    var displayProd={};
    for(var key in prod)displayProd[key]=prod[key];
    displayProd.images=variants[0].images;
    displayProd.img=variants[0].images[0]||prod.img;
    el("pdImg").innerHTML=productCarouselHTML(displayProd,"pd");
  }
}
function pickColorVariant(btn,productId,index){
  var prod=null;
  for(var i=0;i<T[lang].products.length;i++){if(T[lang].products[i].id===productId){prod=T[lang].products[i];break;}}
  if(!prod)return;
  var opts=document.querySelectorAll(".color-opt");for(var j=0;j<opts.length;j++)opts[j].classList.remove("sel");
  if(btn)btn.classList.add("sel");
  var variants=parseColorVariants(prod);
  var displayProd=prod;
  if(index>=0&&variants[index]){
    selColor=variants[index].name;
    selVariantImages=variants[index].images.slice();
    displayProd={};
    for(var key in prod)displayProd[key]=prod[key];
    displayProd.images=variants[index].images;
    displayProd.img=variants[index].images[0]||prod.img;
  }
  el("pdImg").innerHTML=productCarouselHTML(displayProd,"pd");
}
window.pickColorVariant=pickColorVariant;
function togAcc(head){var body=head.nextElementSibling,ico=head.querySelector(".acc-ico"),isOpen=body.classList.contains("open");body.classList.toggle("open",!isOpen);head.classList.toggle("open",!isOpen);ico.textContent=isOpen?"+":"−";}
