function productImgSrc(prod){
  var imgs=productImages(prod);
  return imgs.length?imgs[0]:"";
}

function localizedValue(val,locale){
  if(typeof val==="string")return val;
  if(val&&typeof val==="object"){
    if(val[locale])return val[locale];
    if(val.it)return val.it;
    if(val.en)return val.en;
  }
  return "";
}
function imageList(value){
  if(Array.isArray(value))return value.map(function(v){return String(v||"").trim();}).filter(Boolean);
  if(typeof value==="string"){
    return value.split(/\n|;|,/).map(function(v){return v.trim();}).filter(Boolean);
  }
  return [];
}
function detailValue(details){
  details=details||{};
  for(var i=1;i<arguments.length;i++){
    var key=arguments[i];
    if(details[key])return details[key];
  }
  return "";
}
function detailMaterial(details){
  details=details||{};
  return [details.materiale_cura,details.descrizione_tessuto,details.composizione,details.colore].filter(Boolean).join("\n\n");
}

function fetchJsonFromEndpoints(endpoints){
  if(!window.fetch)return Promise.reject(new Error("fetch unavailable"));
  var idx=0;
  function next(){
    if(idx>=endpoints.length)return Promise.reject(new Error("All endpoints failed"));
    var endpoint=endpoints[idx++];
    return fetch(endpoint,{headers:{"Accept":"application/json"}}).then(function(res){
      if(!res.ok)throw new Error("HTTP "+res.status+" @ "+endpoint);
      return res.json();
    }).catch(function(){
      return next();
    });
  }
  return next();
}

function fetchSupabaseProducts(){
  if(!supabaseReady())return Promise.reject(new Error("Supabase not configured"));
  var query="?select=*&order=sort_order.asc";
  return fetch(supabaseRest(PRODUCTS_TABLE,query),{headers:supabaseHeaders()}).then(function(res){
    if(!res.ok)throw new Error("Supabase products HTTP "+res.status);
    return res.json().then(function(rows){
      return (rows||[]).filter(function(row){
        return row&&row.active!==false&&row.active!=="false"&&row.active!==0&&row.active!=="0";
      });
    });
  });
}

function normalizeBackendProduct(prod,locale){
  var photos=imageList(prod.foto||prod.immagini||prod.images||prod.image_urls||prod.url_immagini);
  var details=prod.details||{};
  var fallbackName=detailValue(details,"nome_prodotto","nome_opera")||prod.slug||prod.id;
  var fallbackSub=detailValue(details,"descrizione","descrizione_prodotto","variante","dimensione_taglia","dimensione","dimensioni");
  var fallbackStory=detailValue(details,"descrizione","descrizione_prodotto","parole_akasha","frasi_akasha");
  return {
    id: prod.id||prod.slug,
    name: localizedValue(prod.nome,locale)||localizedValue(prod.name,locale)||prod.name_it||prod.name_en||fallbackName,
    sub: localizedValue(prod.sottotitolo,locale)||fallbackSub||"",
    price: prod.prezzo||0,
    sizes: prod.taglie||[],
    badge: prod.badge||"",
    bc: prod.badge_class||"",
    img: photos.length?photos[0]:"",
    images: photos,
    material: localizedValue(prod.materiale,locale)||detailMaterial(details),
    story: localizedValue(prod.storia,locale)||fallbackStory||"",
    category: prod.categoria||prod.category||prod.shop_category||detailValue(details,"categoria","categoria_shop","macro_categoria","sottocategoria")||"",
    hide_price: prod.hide_price===true||prod.nascondi_prezzo===true||details.nascondi_prezzo===true||details.nascondi_prezzo==="true"||details.nascondi_prezzo==="1",
    details: details,
    details_labels: prod.details_labels||{},
    stripe_link: prod.stripe_link||""
  };
}

function normalizeCategory(category){
  var value=(category||"").toString().toLowerCase();
  var slug=value.replace(/\s+/g,"-");
  if(value.indexOf("arte")!==-1||value.indexOf("art")!==-1||value.indexOf("opera")!==-1||value.indexOf("poster")!==-1||value.indexOf("stampa")!==-1||value.indexOf("print")!==-1)return "art";
  if(value.indexOf("accessorio-tessile")!==-1||value.indexOf("accessorio tessile")!==-1||value.indexOf("foul")!==-1||value.indexOf("scarf")!==-1||value.indexOf("stola")!==-1)return "body";
  if(slug==="tessile"||slug==="tavola"||slug==="bottiglia"||slug==="tazze")return "home";
  if(value.indexOf("casa")!==-1||value.indexOf("home")!==-1||value.indexOf("living")!==-1||value.indexOf("lifestyle")!==-1||value.indexOf("tessile")!==-1||value.indexOf("tavola")!==-1||value.indexOf("bottiglia")!==-1||value.indexOf("bottle")!==-1||value.indexOf("tazza")!==-1||value.indexOf("cup")!==-1||value.indexOf("ceramic")!==-1||value.indexOf("bicchier")!==-1||value.indexOf("glass")!==-1||value.indexOf("cristall")!==-1||value.indexOf("crystal")!==-1||value.indexOf("cusc")!==-1||value.indexOf("pillow")!==-1||value.indexOf("vaso")!==-1||value.indexOf("piatto")!==-1||value.indexOf("plate")!==-1)return "home";
  if(value.indexOf("abito")!==-1||value.indexOf("abbigl")!==-1||value.indexOf("corpo")!==-1||value.indexOf("bijoux")!==-1||value.indexOf("dress")!==-1||value.indexOf("wear")!==-1||value.indexOf("set")!==-1||value.indexOf("seta")!==-1||value.indexOf("silk")!==-1||value.indexOf("magl")!==-1||value.indexOf("knit")!==-1||value.indexOf("cashmere")!==-1||value.indexOf("cardigan")!==-1||value.indexOf("tunica")!==-1||value.indexOf("tunic")!==-1||value.indexOf("kimono")!==-1)return "body";
  return "all";
}
function normalizeShopCategory(category){
  var value=(category||"").toString().toLowerCase();
  var slug=value.replace(/\s+/g,"-");
  if(slug==="tessile")return "home-textile";
  if(slug==="bottiglia")return "home-bottles";
  if(slug==="tazze")return "home-cups";
  if(slug==="tavola")return "home-table";
  if(slug==="arte")return "art";
  if(slug==="abbigliamento")return "body-clothing";
  if(slug==="bijoux")return "body-bijoux";
  if(slug==="accessorio-tessile")return "body-textile-accessory";
  if(value.indexOf("accessorio-tessile")!==-1||value.indexOf("accessorio tessile")!==-1||value.indexOf("foul")!==-1||value.indexOf("scarf")!==-1||value.indexOf("stola")!==-1||value.indexOf("tessile corpo")!==-1)return "body-textile-accessory";
  if(value.indexOf("bijoux")!==-1||value.indexOf("gioiel")!==-1||value.indexOf("jewel")!==-1||value.indexOf("spilla")!==-1||value.indexOf("brooch")!==-1)return "body-bijoux";
  if(value.indexOf("abbigliamento")!==-1||value.indexOf("abito")!==-1||value.indexOf("dress")!==-1||value.indexOf("wear")!==-1||value.indexOf("seta")!==-1||value.indexOf("silk")!==-1||value.indexOf("magl")!==-1||value.indexOf("knit")!==-1||value.indexOf("cashmere")!==-1||value.indexOf("cardigan")!==-1||value.indexOf("tunica")!==-1||value.indexOf("tunic")!==-1||value.indexOf("kimono")!==-1)return "body-clothing";
  if(value.indexOf("bottiglia")!==-1||value.indexOf("bottle")!==-1||value.indexOf("cristall")!==-1||value.indexOf("crystal")!==-1)return "home-bottles";
  if(value.indexOf("tazza")!==-1||value.indexOf("tazze")!==-1||value.indexOf("cup")!==-1||value.indexOf("ceramic")!==-1)return "home-cups";
  if(value.indexOf("tavola")!==-1||value.indexOf("table")!==-1||value.indexOf("piatto")!==-1||value.indexOf("plate")!==-1||value.indexOf("bicchier")!==-1||value.indexOf("glass")!==-1)return "home-table";
  if(value.indexOf("tessile")!==-1||value.indexOf("cusc")!==-1||value.indexOf("pillow")!==-1||value.indexOf("home")!==-1||value.indexOf("casa")!==-1)return "home-textile";
  if(value.indexOf("arte")!==-1||value.indexOf("art")!==-1||value.indexOf("opera")!==-1||value.indexOf("poster")!==-1||value.indexOf("stampa")!==-1||value.indexOf("print")!==-1)return "art";
  return "all";
}
function productSearchText(prod){
  prod=prod||{};
  var details=prod.details||{};
  return [prod.category,prod.sub,prod.name,prod.material,prod.story,JSON.stringify(details)].join(" ");
}
function productCategoryText(prod){
  prod=prod||{};
  var details=prod.details||{};
  var detailCategory=detailValue(details,"categoria","categoria_shop","macro_categoria","sottocategoria","categoria_prodotto","sezione","famiglia");
  var imagePaths=productImages(prod).join(" ");
  return [prod.category,prod.id,detailCategory,prod.sub,prod.name,imagePaths].join(" ");
}

function getFilteredProducts(products){
  var list=products.slice();
  if(currentFilter==="all")return list;
  return list.filter(function(prod){
    var haystack=productCategoryText(prod);
    var fallback=productSearchText(prod);
    var cat=isShopPage()?normalizeShopCategory(haystack):normalizeCategory(haystack);
    if(cat==="all")cat=isShopPage()?normalizeShopCategory(fallback):normalizeCategory(fallback);
    if(currentFilter==="body")return cat==="body-clothing"||cat==="body-textile-accessory"||cat==="body-bijoux"||normalizeCategory(haystack)==="body";
    if(currentFilter==="home")return cat==="home-textile"||cat==="home-table"||cat==="home-bottles"||cat==="home-cups"||normalizeCategory(haystack)==="home";
    return cat===currentFilter;
  });
}

function updateDynamicSeo(products){
  var old=el("dynamic-product-schema");
  if(old)old.remove();
  var legacy=el("legacy-product-schema");
  if(legacy)legacy.remove();
  var list=products.slice(0,12).map(function(prod,index){
    return {"@type":"ListItem","position":index+1,"item":{"@type":"Product","name":prod.name,"description":prod.story||prod.sub||prod.name,"brand":{"@type":"Brand","name":"Ulakasha"},"category":prod.category||"Luxury fashion","image":productImgSrc(prod)||undefined,"offers":{"@type":"Offer","price":String(prod.price||0),"priceCurrency":"EUR","availability":"https://schema.org/InStock","url":prod.stripe_link||"https://www.ulakasha.com/"}}};
  });
  var script=document.createElement("script");
  script.type="application/ld+json";
  script.id="dynamic-product-schema";
  var isCreazioni=isCreazioniPage();
  script.textContent=JSON.stringify({"@context":"https://schema.org","@type":"CollectionPage","name":isCreazioni?"Creazioni Ulakasha":"Shop Ulakasha","url":isCreazioni?"https://www.ulakasha.com/collezione.html":"https://www.ulakasha.com/shop.html","description":isCreazioni?"Creazioni Ulakasha alimentate dal catalogo admin: abiti, opere d'arte, oggetti per la casa.":"Catalogo shop Ulakasha sincronizzato con backend.","mainEntity":{"@type":"ItemList","itemListElement":list}});
  document.head.appendChild(script);
}

function applyEventData(data){
  if(!data)return;
  eventData=data;
  var title=(data.titolo||"").trim();
  var dates=(data.date||"").trim();
  var place=(data.luogo||"").trim();
  var space=(data.spazio||"").trim();
  var ingresso=(data.ingresso||"").trim();
  if(document.querySelector(".concept-store-page"))set("ev-sup","CONCEPT STORE AURA · MILANO");
  else if(title)set("ev-sup",title+" · Concept Store · Milan Design Week 2026");
  if(dates)set("ev-date",dates);
  if(place){
    var placeHtml=place;
    if(space)placeHtml+= '<br><span style="font-size:15px;color:var(--muted);" id="ev-space-b">'+space+"</span>";
    set("ev-place",placeHtml,true);
  }else if(space){
    set("ev-space",space);
  }
  if(ingresso)set("ev-v3",ingresso);
  var desc=localizedValue(data.descrizione,lang);
  if(desc)set("ev-d1",desc);
  eventLoaded=true;
}

function syncReservationOptions(products){
  var capo=el("res-capo"),size=el("res-size");
  if(!capo||!size)return;
  var t=T[lang];
  var isIt=lang==="it";
  // Group products by category
  var cats={"silk":[],"knit":[],"scarf":[],"accessory":[],"all":[]};
  for(var i=0;i<products.length;i++){
    var cat=normalizeCategory(products[i].category);
    if(cats[cat])cats[cat].push(products[i]);else cats["all"].push(products[i]);
  }
  var capoHtml='<option value="">'+t.optSel+'</option>';
  // Abbigliamento group
  var abbLabel=isIt?"─── Abbigliamento ───":"─── Clothing ───";
  var abbProds=cats["silk"].concat(cats["knit"]).concat(cats["all"]);
  if(abbProds.length>0){
    capoHtml+='<optgroup label="'+abbLabel+'">';
    for(var i=0;i<abbProds.length;i++){
      capoHtml+='<option value="'+abbProds[i].name+'">'+abbProds[i].name+'</option>';
    }
    capoHtml+='</optgroup>';
  }
  // Foulard group
  var fLabel=isIt?"─── Foulard ───":"─── Scarves ───";
  if(cats["scarf"].length>0){
    capoHtml+='<optgroup label="'+fLabel+'">';
    for(var i=0;i<cats["scarf"].length;i++){
      capoHtml+='<option value="'+cats["scarf"][i].name+'">'+cats["scarf"][i].name+'</option>';
    }
    capoHtml+='</optgroup>';
  }
  // Accessori group
  var accLabel=isIt?"─── Casa & Lifestyle ───":"─── Home & Living ───";
  if(cats["accessory"].length>0){
    capoHtml+='<optgroup label="'+accLabel+'">';
    for(var i=0;i<cats["accessory"].length;i++){
      capoHtml+='<option value="'+cats["accessory"][i].name+'">'+cats["accessory"][i].name+'</option>';
    }
    capoHtml+='</optgroup>';
  }
  // Static accessory fallbacks (always shown if no backend accessories)
  if(cats["accessory"].length===0){
    capoHtml+='<optgroup label="'+accLabel+'">';
    capoHtml+='<option value="Bottiglia in Cristallo">'+( isIt?"Bottiglia in Cristallo":"Crystal Bottle")+'</option>';
    capoHtml+='<option value="Bicchieri e Ceramiche">'+( isIt?"Bicchieri e Ceramiche":"Glasses & Ceramics")+'</option>';
    capoHtml+='</optgroup>';
  }
  capoHtml+='<option value="Più capi">'+t.optMore+'</option>';
  capo.innerHTML=capoHtml;
  var seen={},sizeHtml='<option value="">'+t.optSel+'</option>';
  for(var j=0;j<products.length;j++){
    for(var s=0;s<products[j].sizes.length;s++){
      var sz=products[j].sizes[s];
      if(!seen[sz]){seen[sz]=true;sizeHtml+='<option value="'+sz+'">'+sz+'</option>';}
    }
  }
  sizeHtml+='<option value="nda">'+t.optNda+'</option>';
  size.innerHTML=sizeHtml;
}

function applyLoadedProducts(){
  var t=T[lang];
  var filtered=getFilteredProducts(t.products);
  buildPrevGrid(t.products.slice(0,3));
  buildShopGrid(filtered);
  syncArtPreview();
  renderCart();
  renderWishlist();
  syncReservationOptions(t.products);
  set("shop-meta",filtered.length+" · "+t.shopMeta);
  updateDynamicSeo(t.products);
  if(curProd){
    var found=null;
    for(var i=0;i<t.products.length;i++){if(t.products[i].id===curProd.id){found=t.products[i];break;}}
    if(found)openProd(found.id,false);
  }
}

function loadExternalProducts(){
  var endpoints=[
    window.ULAKASHA_PRODUCTS_ENDPOINT,
    "prodotti.json",
    "./prodotti.json",
    "/prodotti.json",
    "backend/ddprodotti.json",
    "./backend/ddprodotti.json",
    "/backend/ddprodotti.json"
  ].filter(Boolean);
  function applyRawProducts(raw){
    T.it.products=raw.map(function(p){return normalizeBackendProduct(p,"it");});
    T.en.products=raw.map(function(p){return normalizeBackendProduct(p,"en");});
    productsLoaded=true;
    applyLoadedProducts();
  }
  if(window.fetch){
    fetchSupabaseProducts().then(function(raw){applyRawProducts(raw||[]);}).catch(function(){
      fetchJsonFromEndpoints(endpoints).then(function(data){
        var raw=data&&data.prodotti?data.prodotti:(data&&data.products?data.products:[]);
        applyRawProducts(raw);
      }).catch(function(err){
        console.error("Ulakasha products load failed:",err);
        applyLoadedProducts();
      });
    });
  }else{
    applyLoadedProducts();
  }
}

function loadEventData(){
  return;
}


// ═══════════════════════════════════════════════════════════════════════
// CHECKOUT — procedi ordine
// ═══════════════════════════════════════════════════════════════════════
function proceedOrder(){
  if(cart.length===0) return;
  var t=T[lang];
  // Build cart summary text
  var lines=[];
  var total=0;
  for(var i=0;i<cart.length;i++){
    var item=cart[i];
    var prod=cartProduct(item);
    if(!prod) continue;
    var price=Number(item.price||prod.price||0),meta=[];
    if(item.color)meta.push(item.color);
    if(item.sz)meta.push(item.sz);
    lines.push((item.name||prod.name)+" · "+meta.join(" · ")+" · x"+item.qty+" · "+money(price*item.qty));
    total+=price*item.qty;
  }
  // Show summary in modal
  var sumEl=el("chkSummary");
  sumEl.innerHTML="";
  for(var k=0;k<lines.length;k++){
    var d=document.createElement("div");
    d.textContent=lines[k];
    sumEl.appendChild(d);
  }
  var totD=document.createElement("div");
  totD.style.cssText="margin-top:8px;font-weight:600;color:var(--blue-d);border-top:1px solid rgba(74,111,165,.15);padding-top:8px;";
  totD.textContent="Totale: "+money(total);
  sumEl.appendChild(totD);
  // Reset name field
  el("chk-name").value="";
  el("chk-note").value="";
  // Open modal, close cart
  closeCart();
  el("chkModal").classList.add("open");
  document.body.style.overflow="hidden";
  setTimeout(function(){el("chk-name").focus();},420);
}
function closeChk(){
  el("chkModal").classList.remove("open");
  document.body.style.overflow="";
}
function buildOrderText(){
  var t=T[lang];
  var name=el("chk-name").value.trim();
  var note=el("chk-note").value.trim();
  var lines=[];
  var total=0;
  for(var i=0;i<cart.length;i++){
    var item=cart[i];
    var prod=cartProduct(item);
    if(!prod) continue;
    var price=Number(item.price||prod.price||0),meta=[];
    if(item.color)meta.push("Colore: "+item.color);
    if(item.sz)meta.push("Taglia: "+item.sz);
    lines.push((item.name||prod.name)+" ("+meta.join(", ")+") x"+item.qty+" — "+money(price*item.qty));
    total+=price*item.qty;
  }
  var txt="Prenotazione Ulakasha\n\n";
  if(name) txt+="Nome: "+name+"\n";
  txt+="\nCapi selezionati:\n";
  for(var k=0;k<lines.length;k++) txt+="• "+lines[k]+"\n";
  txt+="\nTotale: "+money(total);
  txt+="\n\nConcept Store · Via Festa del Perdono 10, Milano · 21–26 aprile 2026";
  if(note) txt+="\n\nNote: "+note;
  return txt;
}
function sendViaWhatsApp(){
  var name=el("chk-name").value.trim();
  if(!name){showNotif(lang==="it"?"Inserisci il tuo nome":"Please enter your name");el("chk-name").focus();return;}
  var txt=buildOrderText();
  var url="https://wa.me/+39contact?text="+encodeURIComponent(txt);
  // Open WhatsApp — fallback to web if app not installed
  window.open("https://api.whatsapp.com/send?text="+encodeURIComponent(txt),"_blank");
  closeChk();
  showNotif(lang==="it"?"Apertura WhatsApp...":"Opening WhatsApp...");
}
function sendViaEmail(){
  var name=el("chk-name").value.trim();
  if(!name){showNotif(lang==="it"?"Inserisci il tuo nome":"Please enter your name");el("chk-name").focus();return;}
  var txt=buildOrderText();
  var subject=encodeURIComponent("Prenotazione Ulakasha — Concept Store");
  var body=encodeURIComponent(txt);
  window.location.href="mailto:contact@ulakasha.com?subject="+subject+"&body="+body;
  setTimeout(function(){
    closeChk();
    showNotif(lang==="it"?"Email pronta — controlla il tuo client":"Email ready — check your mail app");
  },800);
}

