function submitRes(){
  var t = T[lang];
  var name    = el("res-name").value.trim();
  var contact = el("res-contact").value.trim();
  var capo    = el("res-capo").value;
  var size    = el("res-size").value;
  var note    = el("res-note-txt").value.trim();

  if(!name){    showNotif(t.resErrName);    el("res-name").focus();    return; }
  if(!contact){ showNotif(t.resErrContact); el("res-contact").focus(); return; }
  if(!capo){    showNotif(t.resErrCapo);    el("res-capo").focus();    return; }

  // Build mailto
  var subject = encodeURIComponent("Prenotazione Concept Store — " + capo);
  var body = encodeURIComponent(
    "Nome: " + name + "\n" +
    "Contatto: " + contact + "\n" +
    "Capo: " + capo + "\n" +
    "Taglia: " + (size || "da definire") + "\n" +
    (note ? "Note: " + note : "")
  );
  var mailto = "mailto:contact@ulakasha.com?subject=" + subject + "&body=" + body;
  window.location.href = mailto;

  // Show success after short delay
  setTimeout(function(){
    el("resForm").style.display = "none";
    var s = el("resSuccess");
    s.style.display = "block";
    set("succ-h", t.succH);
    set("succ-p", t.succP, true);
  }, 600);
}

