var fBtns=document.querySelectorAll(".f-btn");
for(var fb=0;fb<fBtns.length;fb++){fBtns[fb].addEventListener("click",function(){
  for(var i=0;i<fBtns.length;i++)fBtns[i].classList.remove("on");
  this.classList.add("on");
  if(isShopPage()){
    var shopMap={"f-body":"body","f-clothing":"body-clothing","f-textile-accessory":"body-textile-accessory","f-bijoux":"body-bijoux","f-home":"home","f-home-textile":"home-textile","f-table":"home-table","f-bottles":"home-bottles","f-cups":"home-cups","f-art":"art"};
    currentFilter=shopMap[this.id]||"all";
  }
  else currentFilter=this.id==="fs"?"body":this.id==="fk"?"home":this.id==="ff"?"art":"all";
  closeFilterDropdowns();
  syncArtPreview();
  if(productsLoaded)applyLoadedProducts();
});}
function closeFilterDropdowns(){
  var dds=document.querySelectorAll(".filter-dd");
  for(var i=0;i<dds.length;i++){
    dds[i].classList.remove("open");
    var btn=dds[i].querySelector(".filter-dd-toggle");
    if(btn)btn.setAttribute("aria-expanded","false");
  }
}
var filterToggles=document.querySelectorAll(".filter-dd-toggle");
for(var ft=0;ft<filterToggles.length;ft++){filterToggles[ft].addEventListener("click",function(e){
  e.preventDefault();
  e.stopPropagation();
  var dd=this.closest(".filter-dd");
  var wasOpen=dd&&dd.classList.contains("open");
  closeFilterDropdowns();
  if(dd&&!wasOpen){dd.classList.add("open");this.setAttribute("aria-expanded","true");}
});}
document.addEventListener("click",function(e){if(!e.target.closest(".filter-dd"))closeFilterDropdowns();});
var structuredDataScripts=document.querySelectorAll('script[type="application/ld+json"]');
for(var sds=0;sds<structuredDataScripts.length;sds++){
  var scriptText=structuredDataScripts[sds].textContent||"";
  if(/ProductCollection|ItemList|Product/i.test(scriptText)&&!/BreadcrumbList|FAQPage|Event|ClothingStore/i.test(scriptText)){
    structuredDataScripts[sds].id="legacy-product-schema";
    break;
  }
}
function initReveal(){
  var els=document.querySelectorAll(".page.on .rv");
  var obs=new IntersectionObserver(function(entries){entries.forEach(function(e){if(e.isIntersecting){e.target.classList.add("vis");obs.unobserve(e.target);}});},{threshold:0.1,rootMargin:"0px 0px -40px 0px"});
  els.forEach(function(r){r.classList.remove("vis");obs.observe(r);});
}
applyLang();
ensureWishlistUI();
renderCart();
loadExternalProducts();
loadEventData();
initReveal();
updateCalendarLang();
applyContattiLang();


// ── CALENDAR LANGUAGE SWITCH ─────────────────────────────────────────
function updateCalendarLang(){
  var l=lang;
  document.querySelectorAll('.cal-wd').forEach(function(el){el.textContent=el.dataset[l]||el.textContent;});
  document.querySelectorAll('.cal-theme').forEach(function(el){el.textContent=el.dataset[l]||el.textContent;});
  document.querySelectorAll('.cal-txt').forEach(function(el){el.textContent=el.dataset[l]||el.textContent;});
}

// ── CONTATTI TRANSLATIONS APPLY ──────────────────────────────────────
function applyContattiLang(){
  var t=T[lang];
  function ss(id,val,isH){var e=document.getElementById(id);if(!e)return;if(isH)e.innerHTML=val;else e.textContent=val;}
  ss('ct-sub',t.ctSub);
  ss('ct-h',t.ctH,true);
  ss('ct-p',t.ctP);
  ss('ct-email-sub',t.ctEmail,true);
  ss('ct-ig-sub',t.ctIg);
  ss('ct-press-sub',t.ctPress);
  ss('mb-label-txt',t.mbLabel);
  ss('mb-dates-txt',t.mbDates,true);
  ss('mb-place-txt',t.mbPlace,true);
  ss('mb-vern-txt',t.mbVern);
  ss('mb-cta-txt',t.mbCta);
  // aside
  ss('res-aside-lbl1',t.resAsideLbl1);
  ss('res-aside-p1',t.resAsideP1,true);
  ss('res-aside-lbl2',t.resAsideLbl2);
  ss('res-aside-p2',t.resAsideP2,true);
}

// ── WHATSAPP RESERVATION ─────────────────────────────────────────────
function buildResText(){
  var name=document.getElementById('res-name').value.trim();
  var contact=document.getElementById('res-contact').value.trim();
  var capo=document.getElementById('res-capo').value;
  var size=document.getElementById('res-size').value;
  var note=document.getElementById('res-note-txt').value.trim();
  var txt=(lang==='en'?'Ulakasha Reservation':'Prenotazione Ulakasha')+'\n\n';
  if(name) txt+=(lang==='en'?'Name: ':'Nome: ')+name+'\n';
  if(contact) txt+=(lang==='en'?'Contact: ':'Contatto: ')+contact+'\n';
  if(capo) txt+=(lang==='en'?'Piece: ':'Capo: ')+capo+'\n';
  if(size) txt+=(lang==='en'?'Size: ':'Taglia: ')+size+'\n';
  if(note) txt+=(lang==='en'?'Notes: ':'Note: ')+note+'\n';
  txt+='\nConcept Store · Via Festa del Perdono 10, Milano · 21–26 aprile 2026';
  return txt;
}
function validateRes(){
  var t=T[lang];
  var name=document.getElementById('res-name').value.trim();
  var contact=document.getElementById('res-contact').value.trim();
  var capo=document.getElementById('res-capo').value;
  if(!name){showNotif(t.resErrName);document.getElementById('res-name').focus();return false;}
  if(!contact){showNotif(t.resErrContact);document.getElementById('res-contact').focus();return false;}
  if(!capo){showNotif(t.resErrCapo);document.getElementById('res-capo').focus();return false;}
  return true;
}
function submitResWA(){
  if(!validateRes())return;
  var txt=buildResText();
  window.open('https://api.whatsapp.com/send?text='+encodeURIComponent(txt),'_blank');
  showSuccessRes();
}
function submitResEmail(){
  if(!validateRes())return;
  var txt=buildResText();
  var subject=encodeURIComponent(lang==='en'?'Ulakasha Reservation — Concept Store':'Prenotazione Ulakasha — Concept Store');
  window.location.href='mailto:contact@ulakasha.com?subject='+subject+'&body='+encodeURIComponent(txt);
  setTimeout(showSuccessRes,800);
}
function showSuccessRes(){
  document.getElementById('resForm').style.display='none';
  var s=document.getElementById('resSuccess');
  s.style.display='block';
  var t=T[lang];
  var sh=document.getElementById('succ-h');if(sh)sh.textContent=t.succH;
  var sp=document.getElementById('succ-p');if(sp)sp.innerHTML=t.succP;
}

function scrollToContatti(){window.location.href='contatti.html';}


// ── VENUE SLIDER ─────────────────────────────────────────────────────
var _venueIdx = 0;
function venueGoTo(n){
  _venueIdx = n;
  var track = document.getElementById('venueSliderTrack');
  if(track) track.style.transform = 'translateX(-' + (n * 100) + '%)';
  var dots = document.querySelectorAll('.venue-dot');
  dots.forEach(function(d,i){d.classList.toggle('on', i===n);});
}
function venueSlide(dir){
  var total = document.querySelectorAll('.venue-slide').length;
  venueGoTo((_venueIdx + dir + total) % total);
}
